// ============================================
// FUNCIONES AUXILIARES
// ============================================

function parseDateDDMMYYYY(dateString) {
    /**
     * Parsear fechas en formato DD/MM/YYYY, DD/MM/YY, o número serial de Excel
     * Retorna en formato YYYY-MM-DD para PostgreSQL
     */
    if (!dateString || dateString === '' || dateString === null) {
        return null;
    }

    try {
        // Si es objeto Date, convertir directamente
        if (dateString instanceof Date) {
            const year = dateString.getFullYear();
            const month = String(dateString.getMonth() + 1).padStart(2, '0');
            const day = String(dateString.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        }

        // Si es un número (formato serial de Excel)
        if (typeof dateString === 'number') {
            // Excel guarda las fechas como días desde 1900-01-01
            // Pero Excel tiene un bug: cuenta 1900 como año bisiesto (no lo es)
            // Por eso restamos 1 día si es >= 60 (después del 29 de feb de 1900)
            const excelEpoch = new Date(1900, 0, 1);
            const daysOffset = dateString > 59 ? dateString - 1 : dateString;
            const date = new Date(excelEpoch.getTime() + (daysOffset - 1) * 24 * 60 * 60 * 1000);

            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        }

        // Convertir a string y limpiar
        const dateStr = String(dateString).trim();

        // Si es un string numérico (serial de Excel como string)
        if (/^\d+$/.test(dateStr)) {
            const serialNumber = parseInt(dateStr);
            const excelEpoch = new Date(1900, 0, 1);
            const daysOffset = serialNumber > 59 ? serialNumber - 1 : serialNumber;
            const date = new Date(excelEpoch.getTime() + (daysOffset - 1) * 24 * 60 * 60 * 1000);

            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        }

        // Si viene en formato ISO (2025-02-06T03:00:00.000Z o 2025-02-06)
        if (dateStr.includes('-') && !dateStr.includes('/')) {
            const dt = new Date(dateStr);
            if (!isNaN(dt.getTime())) {
                const year = dt.getFullYear();
                const month = String(dt.getMonth() + 1).padStart(2, '0');
                const day = String(dt.getDate()).padStart(2, '0');
                return `${year}-${month}-${day}`;
            }
        }

        // Si viene en formato DD/MM/YYYY o DD/MM/YY
        if (dateStr.includes('/')) {
            const parts = dateStr.split('/');
            if (parts.length === 3) {
                let day = parts[0].padStart(2, '0');
                let month = parts[1].padStart(2, '0');
                let year = parts[2];

                // Si el año es de 2 dígitos, convertir a 4
                if (year.length === 2) {
                    const yearNum = parseInt(year);
                    // Si es mayor a 50, asumir 19XX, sino 20XX
                    year = yearNum > 50 ? `19${year}` : `20${year}`;
                }

                // Validar que sean números válidos
                const dayNum = parseInt(day);
                const monthNum = parseInt(month);
                const yearNum = parseInt(year);

                if (dayNum >= 1 && dayNum <= 31 && monthNum >= 1 && monthNum <= 12 && yearNum >= 1900) {
                    return `${year}-${month}-${day}`;
                }
            }
        }

        return null;
    } catch (e) {
        console.log(`Error parseando fecha: ${dateString} - ${e.message}`);
        return null;
    }
}

function calcularDiasHastaControl(fechaControlStr, desdeFecha = null) {
    /**
     * Calcular días hasta el próximo control desde una fecha dada (o desde hoy)
     */
    if (!fechaControlStr) {
        return null;
    }

    try {
        // Si viene en formato DD/MM/YYYY, convertir primero
        let fechaISO = fechaControlStr;
        if (typeof fechaControlStr === 'string' && fechaControlStr.includes('/')) {
            fechaISO = parseDateDDMMYYYY(fechaControlStr);
        } else if (typeof fechaControlStr === 'number') {
            // Si es número serial de Excel
            fechaISO = parseDateDDMMYYYY(fechaControlStr);
        }

        const fechaControl = new Date(fechaISO);
        const fechaDesde = desdeFecha ? new Date(desdeFecha) : new Date();

        // Resetear horas para comparar solo fechas
        fechaControl.setHours(0, 0, 0, 0);
        fechaDesde.setHours(0, 0, 0, 0);

        const diffTime = fechaControl - fechaDesde;
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        return diffDays;
    } catch (e) {
        return null;
    }
}

function determinarEstadoControl(diasHastaControl) {
    /**
     * Determinar estado del control basado en días hasta el control
     */
    if (diasHastaControl === null || diasHastaControl === undefined) {
        return 'pendiente';
    }

    if (diasHastaControl < 0) {
        return 'vencido';
    } else if (diasHastaControl === 0) {
        return 'realizado';
    } else {
        return 'pendiente';
    }
}

function buscarSemaforoEnData(data) {
    /**
     * Buscar el color del semáforo en CUALQUIER valor del objeto data
     * Retorna: 'verde', 'amarillo', 'rojo' o 'sin_clasificar'
     */
    const coloresValidos = ['verde', 'amarillo', 'rojo'];

    // Obtener todos los valores del objeto (sin importar las claves)
    const valores = Object.values(data);

    // Buscar en cada valor
    for (const valor of valores) {
        // Si el valor existe y no es null/undefined/vacío
        if (valor !== null && valor !== undefined && valor !== '') {
            // Convertir a string y normalizar
            const valorStr = String(valor).toLowerCase().trim();

            // Verificar si es alguno de los colores válidos
            for (const color of coloresValidos) {
                if (valorStr === color) {
                    return color;
                }
            }
        }
    }

    // Si no se encontró ningún color
    return 'sin_clasificar';
}

function buscarFaseEnData(data) {
    /**
     * Buscar la fase en CUALQUIER valor del objeto data
     * Retorna: 'fase 1', 'fase 2', 'fase 3' o 'fase 1' (default)
     */
    const valores = Object.values(data);

    // Buscar en cada valor
    for (const valor of valores) {
        // Si el valor existe y no es null/undefined/vacío
        if (valor !== null && valor !== undefined && valor !== '') {
            // Convertir a string y normalizar
            const valorStr = String(valor).toLowerCase().trim();

            // Buscar "fase 3" primero (para evitar que "fase 3" sea detectado como "fase" + "3")
            if (valorStr.includes('fase 3') || valorStr === '3' || valorStr === 'fase3') {
                return 'fase 3';
            }

            // Buscar "fase 2"
            if (valorStr.includes('fase 2') || valorStr === '2' || valorStr === 'fase2') {
                return 'fase 2';
            }

            // Buscar "fase 1"
            if (valorStr.includes('fase 1') || valorStr === '1' || valorStr === 'fase1') {
                return 'fase 1';
            }
        }
    }

    // Si no se encontró ninguna fase, retornar fase 1 por defecto
    return 'fase 1';
}

function limpiarTexto(texto) {
    /**
     * Limpiar y normalizar texto
     */
    if (!texto || texto === '') {
        return null;
    }
    return String(texto).trim();
}

function escaparSQL(texto) {
    /**
     * Escapar comillas simples para SQL
     */
    if (!texto) {
        return null;
    }
    return String(texto).replace(/'/g, "''");
}

// ============================================
// PROCESAMIENTO PRINCIPAL
// ============================================

// Obtener todos los items del input
const items = $input.all();
const transformedData = [];

// Fecha actual para los controles realizados (población inicial)
const hoy = new Date();
const fechaHoy = `${hoy.getFullYear()}-${String(hoy.getMonth() + 1).padStart(2, '0')}-${String(hoy.getDate()).padStart(2, '0')}`;

console.log(`📊 Iniciando procesamiento de ${items.length} registros...`);
console.log(`📅 Fecha de ejecución: ${fechaHoy}`);

// Procesar cada item
for (let idx = 0; idx < items.length; idx++) {
    try {
        const data = items[idx].json;

        // Extraer datos principales
        const ciaNombre = limpiarTexto(data.CIA) || 'SIN_CIA';
        const distritoNombre = limpiarTexto(data.DISTRITO) || 'SIN_DISTRITO';
        const baseOfNombre = limpiarTexto(data['Base/Of']) || 'SIN_BASE';

        // Datos del paciente
        const pacienteNombre = limpiarTexto(data['Apellido y Nombre']) || 'DESCONOCIDO';
        const pacienteLegajo = data.Legajo || data['Legajo con ceros'] || 0;
        const pacienteLegajoConCeros = data['Legajo con ceros'] || pacienteLegajo;

        // Fechas (ahora usando la función correcta)
        const fechaInicio = parseDateDDMMYYYY(data['Fecha de Inicio']);
        const fechaProximoControlRaw = data['Próximo Control'];
        const fechaProximoControl = parseDateDDMMYYYY(fechaProximoControlRaw);

        // Diagnóstico
        const diagnosticoNombre = limpiarTexto(data['Diagnóstico']) || 'Sin diagnóstico';

        // Tipo de evento
        const tipoEvento = limpiarTexto(data['Tipo de Evento']) || 'ENFERMO';

        // Métricas de control
        let diasHastaControl = data['DIAS HASTA CONTROL'];
        if (diasHastaControl === null || diasHastaControl === undefined) {
            if (fechaProximoControlRaw) {
                diasHastaControl = calcularDiasHastaControl(fechaProximoControlRaw);
            }
        }

        // Semáforo: Buscar en todos los valores del data
        const semaforoColor = buscarSemaforoEnData(data);

        // Fase: buscar en cualquier campo del data
        const faseNombre = buscarFaseEnData(data);

        // Estado del control ACTUAL: para población inicial, todos son 'realizado'
        const estadoControlActual = 'realizado';

        // PRÓXIMO CONTROL: calcular días y estado
        const diasHastaProximoControl = fechaProximoControl ? calcularDiasHastaControl(fechaProximoControl) : null;
        const estadoProximoControl = determinarEstadoControl(diasHastaProximoControl);

        // Observaciones (POBLACIÓN INICIAL: observacion y observacion_original son iguales)
        const observacionesTexto = limpiarTexto(data.OBSERVACIONES);

        // Metadata adicional
        const equipo = data.Equipo;
        const operadora = limpiarTexto(data.Operadora);
        const diasBaja = data['Días de BAJA'];

        // ============================================
        // CONSTRUIR OBJETO TRANSFORMADO
        // ============================================

        const transformed = {
            // === DATOS DE CIA ===
            cia: {
                nombre: escaparSQL(ciaNombre)
            },

            // === DATOS DE DISTRITO ===
            distrito: {
                nombre: escaparSQL(distritoNombre)
            },

            // === DATOS DE BASE OF ===
            base_of: {
                nombre: escaparSQL(baseOfNombre)
            },

            // === DATOS DEL PACIENTE ===
            paciente: {
                nombre_apellido: escaparSQL(pacienteNombre),
                legajo: pacienteLegajo ? parseInt(pacienteLegajo) : 0,
                legajo_con_ceros: pacienteLegajoConCeros ? parseInt(pacienteLegajoConCeros) : 0
            },

            // === DATOS DEL DIAGNÓSTICO ===
            diagnostico: {
                nombre: escaparSQL(diagnosticoNombre)
            },

            // === DATOS DEL CASO CLÍNICO ===
            caso_clinico: {
                fecha_inicio: fechaInicio,
                tipo_evento: tipoEvento,
                origen_csv_drive: 'HCTest Hoja 1.xlsx',
                fase_nombre: faseNombre,
                semaforo_color: semaforoColor
            },

            // === DATOS DEL CONTROL ACTUAL ===
            // Para población inicial: el control se considera ejecutado HOY
            control: {
                fecha_control: fechaHoy,  // Fecha actual (cuando se ejecutó)
                fecha_ejecucion_control: fechaHoy,  // Fecha actual (cuando se ejecutó)
                dias_hasta_control: diasHastaControl,
                estado_control: estadoControlActual,  // 'realizado' para población inicial
                semaforo_color: semaforoColor,
                fase_nombre: faseNombre,
                observacion: escaparSQL(observacionesTexto),  // Observación procesada
                observacion_original: escaparSQL(observacionesTexto)  // Misma en población inicial
            },

            // === PRÓXIMO CONTROL (del Excel) ===
            // Este es el control futuro que debe crearse
            proximo_control: {
                fecha_control: fechaProximoControl,  // Fecha del Excel
                fecha_ejecucion_control: null,  // Aún no se ejecutó
                dias_hasta_control: diasHastaProximoControl,  // Días desde hoy
                estado_control: estadoProximoControl,  // 'pendiente', 'vencido', etc
                semaforo_color: null,  // Se determinará cuando se ejecute
                fase_nombre: null,  // Se determinará cuando se ejecute
                observacion: null,  // No hay observación aún
                observacion_original: null  // No hay observación aún
            },

            // === METADATA ADICIONAL ===
            metadata: {
                equipo: equipo,
                operadora: escaparSQL(operadora),
                dias_baja: diasBaja
            },

            // === DATOS ORIGINALES (para debugging) ===
            _raw: {
                indice: idx,
                procesado_en: new Date().toISOString(),
                fecha_inicio_original: data['Fecha de Inicio'],
                proximo_control_original: data['Próximo Control']
            }
        };

        transformedData.push(transformed);

    } catch (e) {
        console.log(`❌ Error procesando item ${idx}: ${e.message}`);
        console.log(`   Datos: ${JSON.stringify(items[idx].json, null, 2)}`);
        continue;
    }
}

console.log(`✅ Procesados ${transformedData.length} registros exitosamente`);

return transformedData;
